INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Cable_Crossover','Cable Crossover','pecho',ARRAY['hombros'],'cable','strength',ARRAY['To get yourself into the starting position, place the pulleys on a high position (above your head), select the resistance to be used and hold the pulleys in each hand.','Step forward in front of an imaginary straight line between both pulleys while pulling your arms together in front of you. Your torso should have a small forward bend from the waist. This will be your starting position.','With a slight bend on your elbows in order to prevent stress at the biceps tendon, extend your arms to the side (straight out at both sides) in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms and torso should remain stationary; the movement should only occur at the shoulder joint.','Return your arms back to the starting position as you breathe out. Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the starting position and repeat the movement for the prescribed amount of repetitions.'],'To get yourself into the starting position, place the pulleys on a high position (above your head), select the resistance to be used and hold the pulleys in each hand. Step forward in front of an imaginary straight line between both pulleys while pulling your arms together in front of you. Your torso should have a small forward bend from the waist. This will be your starting position. With a slight bend on your elbows in order to prevent stress at the biceps tendon, extend your arms to the side (straight out at both sides) in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms and torso should remain stationary; the movement should only occur at the shoulder joint. Return your arms back to the starting position as you breathe out. Make sure to use the same arc of motion used to lower the weights. Hold for a second at the starting position and repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Crossover/0.jpg','exercisedb',true),('Cable_Crunch','Cable Crunch','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Kneel below a high pulley that contains a rope attachment.','Grasp cable rope attachment and lower the rope until your hands are placed next to your face.','Flex your hips slightly and allow the weight to hyperextend the lower back. This will be your starting position.','With the hips stationary, flex the waist as you contract the abs so that the elbows travel towards the middle of the thighs. Exhale as you perform this portion of the movement and hold the contraction for a second.','Slowly return to the starting position as you inhale. Tip: Make sure that you keep constant tension on the abs throughout the movement. Also, do not choose a weight so heavy that the lower back handles the brunt of the work.','Repeat for the recommended amount of repetitions.'],'Kneel below a high pulley that contains a rope attachment. Grasp cable rope attachment and lower the rope until your hands are placed next to your face. Flex your hips slightly and allow the weight to hyperextend the lower back. This will be your starting position. With the hips stationary, flex the waist as you contract the abs so that the elbows travel towards the middle of the thighs. Exhale as you perform this portion of the movement and hold the contraction for a second. Slowly return to the starting position as you inhale. Tip: Make sure that you keep constant tension on the abs throughout the movement. Also, do not choose a weight so heavy that the lower back handles the brunt of the work. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Crunch/0.jpg','exercisedb',true),('Cable_Deadlifts','Cable Deadlifts','cuádriceps',ARRAY['antebrazos','glúteos','isquiotibiales','espalda baja'],'cable','strength',ARRAY['Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights.','To begin, squat down be flexing your hips and knees until you can reach the handles.','After grasping them, begin your ascent. Driving through your heels extend your hips and knees keeping your hands hanging at your side. Keep your head and chest up throughout the movement.','After reaching a full standing position, Return to the starting position and repeat.'],'Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights. To begin, squat down be flexing your hips and knees until you can reach the handles. After grasping them, begin your ascent. Driving through your heels extend your hips and knees keeping your hands hanging at your side. Keep your head and chest up throughout the movement. After reaching a full standing position, Return to the starting position and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Deadlifts/0.jpg','exercisedb',true),('Cable_Hammer_Curls_-_Rope_Attachment','Cable Hammer Curls - Rope Attachment','bíceps',ARRAY[]::text[],'cable','strength',ARRAY['Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.','Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.','Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position.','Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary.','After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position.','Repeat for the recommended amount of repetitions.'],'Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it. Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary. Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position. Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary. After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Hammer_Curls_-_Rope_Attachment/0.jpg','exercisedb',true),('Cable_Hip_Adduction','Cable Hip Adduction','cuádriceps',ARRAY[]::text[],'cable','strength',ARRAY['Stand in front of a low pulley facing forward with one leg next to the pulley and the other one away.','Attach the ankle cuff to the cable and also to the ankle of the leg that is next to the pulley.','Now step out and away from the stack with a wide stance and grasp the bar of the pulley system.','Stand on the foot that does not have the ankle cuff (the far foot) and allow the leg with the cuff to be pulled towards the low pulley. This will be your starting position.','Now perform the movement by moving the leg with the ankle cuff in front of the far leg by using the inner thighs to abduct the hip. Breathe out during this portion of the movement.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions and then repeat the same movement with the opposite leg.'],'Stand in front of a low pulley facing forward with one leg next to the pulley and the other one away. Attach the ankle cuff to the cable and also to the ankle of the leg that is next to the pulley. Now step out and away from the stack with a wide stance and grasp the bar of the pulley system. Stand on the foot that does not have the ankle cuff (the far foot) and allow the leg with the cuff to be pulled towards the low pulley. This will be your starting position. Now perform the movement by moving the leg with the ankle cuff in front of the far leg by using the inner thighs to abduct the hip. Breathe out during this portion of the movement. Slowly return to the starting position as you breathe in. Repeat for the recommended amount of repetitions and then repeat the same movement with the opposite leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Hip_Adduction/0.jpg','exercisedb',true),('Cable_Incline_Pushdown','Cable Incline Pushdown','dorsales',ARRAY[]::text[],'cable','strength',ARRAY['Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.','Grasp the straight bar attachment overhead with a pronated (overhand; palms down) shoulder width grip and extend your arms in front of you. The bar should be around 2 inches away from your upper thighs. This will be your starting position.','Keeping the upper arms stationary, lift your arms back in a semi circle until the bar is straight over your head. Breathe in during this portion of the movement.','Slowly go back to the starting position using your lats and hold the contraction once you reach the starting position. Breathe out during the execution of this movement.','Repeat for the recommended amount of repetitions.'],'Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it. Grasp the straight bar attachment overhead with a pronated (overhand; palms down) shoulder width grip and extend your arms in front of you. The bar should be around 2 inches away from your upper thighs. This will be your starting position. Keeping the upper arms stationary, lift your arms back in a semi circle until the bar is straight over your head. Breathe in during this portion of the movement. Slowly go back to the starting position using your lats and hold the contraction once you reach the starting position. Breathe out during the execution of this movement. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Incline_Pushdown/0.jpg','exercisedb',true),('Cable_Incline_Triceps_Extension','Cable Incline Triceps Extension','tríceps',ARRAY[]::text[],'cable','strength',ARRAY['Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.','Grasp the straight bar attachment overhead with a pronated (overhand; palms down) narrow grip (less than shoulder width) and keep your elbows tucked in to your sides. Your upper arms should create around a 25 degree angle when measured from the floor.','Keeping the upper arms stationary, extend the arms as you flex the triceps. Breathe out during this portion of the movement and hold the contraction for a second.','Slowly go back to the starting position.','Repeat for the recommended amount of repetitions.'],'Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it. Grasp the straight bar attachment overhead with a pronated (overhand; palms down) narrow grip (less than shoulder width) and keep your elbows tucked in to your sides. Your upper arms should create around a 25 degree angle when measured from the floor. Keeping the upper arms stationary, extend the arms as you flex the triceps. Breathe out during this portion of the movement and hold the contraction for a second. Slowly go back to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Incline_Triceps_Extension/0.jpg','exercisedb',true),('Cable_Internal_Rotation','Cable Internal Rotation','hombros',ARRAY[]::text[],'cable','strength',ARRAY['Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley''''s height, you can use a flat bench to sit on instead.','Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position.','Pull the single hand cable attachment toward your body by internally rotating your shoulder until your forearm is across your abs. You will be creating an imaginary semi-circle. Tip: The forearm should be perpendicular to your torso at all times.','Slowly go back to the initial position.','Repeat for the recommended amount of repetitions and then repeat the movement with the next arm.'],'Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley''s height, you can use a flat bench to sit on instead. Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position. Pull the single hand cable attachment toward your body by internally rotating your shoulder until your forearm is across your abs. You will be creating an imaginary semi-circle. Tip: The forearm should be perpendicular to your torso at all times. Slowly go back to the initial position. Repeat for the recommended amount of repetitions and then repeat the movement with the next arm.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Internal_Rotation/0.jpg','exercisedb',true),('Cable_Iron_Cross','Cable Iron Cross','pecho',ARRAY[]::text[],'cable','strength',ARRAY['Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.','Stand directly between both pulleys with your arms extended out to your sides. Your head and chest should be up while your arms form a "T". This will be your starting position.','Keeping the elbows extended, pull your arms straight to your sides.','Return your arms back to the starting position after a pause at the peak contraction.','Continue the movement for the prescribed number of repetitions.'],'Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand. Stand directly between both pulleys with your arms extended out to your sides. Your head and chest should be up while your arms form a "T". This will be your starting position. Keeping the elbows extended, pull your arms straight to your sides. Return your arms back to the starting position after a pause at the peak contraction. Continue the movement for the prescribed number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Iron_Cross/0.jpg','exercisedb',true),('Cable_Judo_Flip','Cable Judo Flip','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands.','Twist your body away from the pulley as you bring the rope over your shoulder like you''''re performing a judo flip.','Shift your weight between your feet as you twist and crunch forward, pulling the cable downward.','Return to the starting position and repeat until failure.','Then, reposition and repeat the same series of movements on the opposite side.'],'Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands. Twist your body away from the pulley as you bring the rope over your shoulder like you''re performing a judo flip. Shift your weight between your feet as you twist and crunch forward, pulling the cable downward. Return to the starting position and repeat until failure. Then, reposition and repeat the same series of movements on the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Judo_Flip/0.jpg','exercisedb',true);